module top_module(
    input [3:0] bin,
    output reg [6:0] disp_out
);

    // Always block triggered on any change of input
    always @(*) begin
        case (bin)
            4'd0: disp_out = 7'b0111111;
            4'd1: disp_out = 7'b0000110;
            4'd2: disp_out = 7'b1011011;
            4'd3: disp_out = 7'b1001111;
            4'd4: disp_out = 7'b1100110;
            4'd5: disp_out = 7'b1101101;
            4'd6: disp_out = 7'b1111101;
            4'd7: disp_out = 7'b0000111;
            4'd8: disp_out = 7'b1111111;
            4'd9: disp_out = 7'b1101111;
            default: disp_out = 7'b0000000;  // Turn off for values 10-15
        endcase
    end

endmodule
